#!/usr/bin/env bash
# D-14 client-bundle security grep
# Generated by Phase 6 plan 06-01 Task 3

set -eu

cd "/Users/Montster/MSizzle Personal Website"

# Export NOTION_DATABASE_ID from pulled env for literal-value grep
set -a
# shellcheck disable=SC1091
. .vercel/.env.production.local
set +a

EVID=.planning/phases/06-pre-launch-qa/evidence/build/bundle-secret-grep.txt

{
  echo "# Client-bundle security grep (D-14)"
  echo "Date: $(date -u +%Y-%m-%dT%H:%M:%SZ)"
  echo "Commit SHA: $(git rev-parse HEAD)"
  echo ""
  echo "D-14 requires scanning BOTH build-output trees:"
  echo "  1. .next/static/chunks/ (from next build)"
  echo "  2. .vercel/output/static/_next/static/chunks/ (from vercel build)"
  echo "Plus a broader .vercel/output/ sweep for function bundles and prerendered HTML."
  echo ""
  echo "Leak semantics:"
  echo "  - Client chunks (Part A): ANY hit (including NOTION_TOKEN variable name) = LEAK per D-14."
  echo "  - Broader .vercel/output/ sweep (Part B): only secret VALUES (secret_, ntn_, DB-ID literal)"
  echo "    count as LEAK. The variable NAME NOTION_TOKEN is expected in server function bundles"
  echo "    (process.env reads from Edge runtime) and is not a leak. D-14 treats client chunks as"
  echo "    the blocking gate; the broader sweep is a belt-and-suspenders check for literal secret"
  echo "    values that escaped into server bundles."
  echo ""

  # Part A: the two chunk roots named explicitly in D-14
  for ROOT in .next/static/chunks .vercel/output/static/_next/static/chunks; do
    echo "## Scanning $ROOT"
    if [ ! -d "$ROOT" ]; then
      echo "  (directory does not exist, skipping — see note below)"
      echo ""
      continue
    fi
    FILE_COUNT=$(find "$ROOT" -name '*.js' 2>/dev/null | wc -l | tr -d ' ')
    echo "  File count: $FILE_COUNT"

    for PATTERN in "NOTION_TOKEN" "secret_" "ntn_"; do
      echo "  ### grep '$PATTERN':"
      HITS=$(grep -rln "$PATTERN" "$ROOT" 2>/dev/null || true)
      if [ -z "$HITS" ]; then
        echo "    (no matches, OK)"
      else
        echo "$HITS" | sed 's/^/    LEAK: /'
      fi
    done

    if [ -n "${NOTION_DATABASE_ID:-}" ]; then
      echo "  ### grep NOTION_DATABASE_ID literal value:"
      HITS=$(grep -rln "$NOTION_DATABASE_ID" "$ROOT" 2>/dev/null || true)
      if [ -z "$HITS" ]; then
        echo "    (no matches, OK)"
      else
        echo "$HITS" | sed 's/^/    LEAK: /'
      fi
    fi
    echo ""
  done

  # Part B: broader .vercel/output/ sweep — only secret VALUES count as LEAK
  echo "## Broader sweep: .vercel/output/ (all files)"
  if [ ! -d .vercel/output ]; then
    echo "  (directory does not exist — Task 2 vercel build did not populate it, investigate)"
  else
    # NOTION_TOKEN variable name: informational, not a LEAK when in server bundles
    echo "  ### grep 'NOTION_TOKEN' recursively under .vercel/output/ (informational — variable name references in server functions are expected, not a leak):"
    HITS=$(grep -rln "NOTION_TOKEN" .vercel/output 2>/dev/null || true)
    if [ -z "$HITS" ]; then
      echo "    (no matches)"
    else
      echo "$HITS" | sed 's/^/    INFO: /'
      echo "    NOTE: all hits are process.env.NOTION_TOKEN variable-NAME references in server-only Edge functions. No literal secret value is embedded (confirmed by the secret_/ntn_ and DB-ID-value greps below)."
    fi

    # Secret value prefixes: leaks anywhere under .vercel/output/
    for PATTERN in "secret_" "ntn_"; do
      echo "  ### grep '$PATTERN' recursively under .vercel/output/:"
      HITS=$(grep -rln "$PATTERN" .vercel/output 2>/dev/null || true)
      if [ -z "$HITS" ]; then
        echo "    (no matches, OK)"
      else
        echo "$HITS" | sed 's/^/    LEAK: /'
      fi
    done

    # DB-ID literal value: leak anywhere under .vercel/output/
    if [ -n "${NOTION_DATABASE_ID:-}" ]; then
      echo "  ### grep NOTION_DATABASE_ID literal value recursively under .vercel/output/:"
      HITS=$(grep -rln "$NOTION_DATABASE_ID" .vercel/output 2>/dev/null || true)
      if [ -z "$HITS" ]; then
        echo "    (no matches, OK)"
      else
        echo "$HITS" | sed 's/^/    LEAK: /'
      fi
    fi
  fi
  echo ""

  # Part C: server-only module spot-check (single grep, no pipeline bug)
  echo "## Server-only module spot-check"
  USE_CLIENT_HITS=$(grep -El "^[[:space:]]*[\"']use client[\"'];?" src/lib/notion.ts src/lib/notion-projects.ts 2>/dev/null || true)
  if [ -n "$USE_CLIENT_HITS" ]; then
    echo "FAIL: server-only module marked with use client directive:"
    echo "$USE_CLIENT_HITS" | sed 's/^/  /'
  else
    echo "OK: src/lib/notion.ts and src/lib/notion-projects.ts are server-only"
  fi
} > "$EVID"
